<Project>
  <PropertyGroup>
    <!-- Centralized settings to prevent dependency confusion across all projects in the repo -->
    <TreatWarningsAsErrors>true</TreatWarningsAsErrors>
    <!-- Fail the build if package source mapping cannot resolve a package -->
    <RestorePackagesWithLockFile>true</RestorePackagesWithLockFile>
  </PropertyGroup>

  <!-- 
    Security note: Package Source Mapping in NuGet.config ensures that:
    - Company.* packages can ONLY be resolved from CompanyPrivateFeed
    - All other packages can ONLY be resolved from nuget.org
    - This prevents dependency confusion attacks where an attacker publishes
      a malicious "Company.SharedLibrary" or "Company.Authentication" package
      on nuget.org with a higher version number.
    
    The <clear /> directive in packageSources removes any inherited/default
    sources, ensuring only explicitly listed sources are used.
    
    RestoreLockedMode in CI ensures the lock file is respected and no
    unexpected package version changes occur during CI builds.
  -->
</Project>